from dataclasses import dataclass, field


@dataclass
class RiskRegister:
    feature_id: str
    system_prompt_version: str
    entries: list[RiskEntry] = field(default_factory=list)
    last_reviewed_at: str = ""
    reviewed_by: str = ""

    def add(self, entry: RiskEntry) -> None:
        self.entries.append(entry)

    def release_blocking_risks(self) -> list[RiskEntry]:
        return [e for e in self.entries if e.is_release_blocking]

    def is_release_ready(self) -> bool:
        return len(self.release_blocking_risks()) == 0

    def by_category(self) -> dict[RiskCategory, list[RiskEntry]]:
        result: dict[RiskCategory, list[RiskEntry]] = {}
        for entry in self.entries:
            result.setdefault(entry.category, []).append(entry)
        return result

    def open_high_or_critical(self) -> list[RiskEntry]:
        return [
            e for e in self.entries
            if e.status == RiskStatus.OPEN
            and e.risk_level() in ("HIGH", "CRITICAL")
        ]

    def summary(self) -> dict:
        return {
            "total": len(self.entries),
            "open": sum(1 for e in self.entries if e.status == RiskStatus.OPEN),
            "release_blocking": len(self.release_blocking_risks()),
            "is_release_ready": self.is_release_ready(),
            "open_high_or_critical": [e.risk_id for e in self.open_high_or_critical()],
        }
